import{_ as o,o as a,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"67. Family Violence Leave","description":"","frontmatter":{"title":"67. Family Violence Leave","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","family-violence-leave","preliminary","definitions"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/leave/67-family-violence-leave.md","filePath":"ebas/has-managers-admin/common-terms/leave/67-family-violence-leave.md"}'),t={name:"ebas/has-managers-admin/common-terms/leave/67-family-violence-leave.md"};function r(s,e,l,p,c,m){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_67-family-violence-leave" tabindex="-1">67. Family Violence Leave <a class="header-anchor" href="#_67-family-violence-leave" aria-label="Permalink to &quot;67. Family Violence Leave&quot;">​</a></h1><p>NOTE: Family member is defined in section 8 of the Family Violence Protection Act 2008 (Vic) and is broader than the definition of immediate family in <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/6-definitions.html">clause 6</a> (Definitions).</p><p><strong>67.1</strong> General Principle</p><p><strong>(a)</strong> Each Employer recognises that Employees sometimes face situations of violence or abuse in their personal life that may affect their attendance or performance at work. Therefore, each Employer</p><p>is committed to providing support to staff that experience family violence.</p><p><strong>(b)</strong> Leave for family violence purposes is available to employees who are experiencing family violence to allow them to be absent from the workplace to attend counselling appointments, medical appointments, legal proceedings or appointments with a legal practitioner and other activities related to, and as a consequence of, family violence.</p><p><strong>67.2</strong> Definition of Family Violence For the purposes of this clause, family violence is as defined by the Family Violence Protection Act 2008 (Vic) which defines family violence at section 5, in part, as follows:</p><p><strong>(a)</strong> behaviour by a person towards a family member of that person if that behaviour:</p><p><strong>(i)</strong> is physically or sexually abusive; or</p><p><strong>(ii)</strong> is emotionally or psychologically abusive; or</p><p><strong>(iii)</strong> is economically abusive; or</p><p><strong>(iv)</strong> is threatening; or</p><p><strong>(v)</strong> is coercive; or</p><p><strong>(vi)</strong> in any other way controls or dominates the family member and causes that family member to feel fear for the safety or wellbeing of that family member or another person; or</p><p><strong>(vii)</strong> behaviour by a person that causes a child to hear or witness, or otherwise be exposed to the effects of, behaviour referred to in subclause 67.2(a) above.</p><p><strong>67.3</strong> Eligibility</p><p><strong>(a)</strong> Paid leave for family violence purposes is available to all Employees with the exception of casual Employees.</p><p><strong>(b)</strong> Casual Employees are entitled to access leave without pay for family violence purposes.</p><p><strong>67.4</strong> General Measures</p><p><strong>(a)</strong> Evidence of family violence may be required and can be in the form an agreed document issued by the Police Service, a Court, a registered health practitioner, a Family Violence Support Service, district nurse, maternal and health care nurse or Lawyer. A signed statutory declaration can also be offered as evidence.</p><p><strong>(b)</strong> All personal information concerning family violence will be kept confidential in line with the Employer’s policies and relevant</p><p>legislation. No information will be kept on an Employee’s personnel file without their express written permission.</p><p><strong>(c)</strong> No adverse action will be taken against an Employee if their attendance or performance at work suffers as a result of experiencing family violence.</p><p><strong>(d)</strong> The Employer will identify contact/s within the workplace who will be trained in family violence and associated privacy issues. The Employer will advertise the name of any Family Violence contacts within the workplace.</p><p><strong>(e)</strong> An Employee experiencing family violence may raise the issue with their immediate supervisor, Family Violence contacts, union delegate or nominated Human Resources contact. The immediate supervisor may seek advice from Human Resources if the Employee chooses not to see the Human Resources or Family Violence contact.</p><p><strong>(f)</strong> Where requested by an Employee, the Human Resources contact will liaise with the Employee’s manager on the Employee’s behalf, and will make a recommendation on the most appropriate form of support to provide in accordance with subclause 67.5 and subclause 67.6.</p><p><strong>(g)</strong> The Employer will develop guidelines to supplement this clause and which details the appropriate action to be taken in the event that an employee reports family violence.</p><p><strong>67.5</strong> Leave</p><p><strong>(a)</strong> An Employee experiencing family violence will have access to 20 days per year of paid special leave (pro-rata for part-time Employees) for counselling appointments, medical appointments, legal proceedings or appointments with a legal practitioner, and other activities related to, and as a consequent of, family violence (this leave is not cumulative but if the leave is exhausted consideration will be given to providing additional leave). This leave will be in addition to existing leave entitlements and may be taken as consecutive or single days or as a fraction of a day and can be taken without prior approval.</p><p><strong>(b)</strong> An Employee who supports a person experiencing family violence may utilise their personal leave entitlement to accompany them to court, to hospital, or to care for children. The Employer may require evidence consistent with subclause 67.4(a) from an Employee seeking to utilise their personal/carer’s leave entitlement.</p><p><strong>67.6</strong> Individual Support</p><p><strong>(a)</strong> In order to provide support to an Employee experiencing family violence and to provide a safe work environment to all Employees,</p><p>the Employer will approve any reasonable request from an Employee experiencing family violence for:</p><p><strong>(i)</strong> temporary or ongoing changes to their span of hours or pattern or hours and/or shift patterns;</p><p><strong>(ii)</strong> temporary or ongoing job redesign or changes to duties;</p><p><strong>(iii)</strong> temporary or ongoing relocation to suitable employment;</p><p><strong>(iv)</strong> a change to their telephone number or email address to avoid harassing contact;</p><p><strong>(v)</strong> any other appropriate measure including those available under existing provisions for family friendly and flexible work arrangements.</p><p><strong>(b)</strong> Any changes to an Employee’s role should be reviewed at agreed periods. When an Employee is no longer experiencing family violence, the terms and conditions of employment may revert back to the terms and conditions applicable to the Employee’s substantive position.</p><p><strong>(c)</strong> An Employee experiencing family violence will be offered access to the Employee Assistance Program (EAP) and/or other available local employee support resources. The EAP will include professionals trained specifically in family violence.</p><p><strong>(d)</strong> An Employee that discloses that they are experiencing family violence will be given information regarding current support services</p><p>Plain language terms: DV leave, domestic violence, family violence, abuse leave.</p>',42)])])}const d=o(t,[["render",r]]);export{h as __pageData,d as default};
